#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int N;
    cin >> N;

    vector<string> a(N);
    for (int i = 0; i < N; ++i) {
        cin >> a[i];
    }

    // For each name, produce its "sorted-letter" canonical form.
    // Also store original index.
    vector<pair<string, int>> sorted(N);
    for (int i = 0; i < N; ++i) {
        string s = a[i];
        sort(s.begin(), s.end());
        sorted[i] = {s, i};
    }

    // Sort by canonical form (and by original index for tie-breaking).
    sort(sorted.begin(), sorted.end());

    // For each position in sorted order, the "lowest possible original position"
    // for this canonical key is determined by the first occurrence of that key,
    // and the "highest possible original position" by the last occurrence.
    // We'll compute answer for each original index.
    vector<int> lo(N), hi(N);
    int i = 0;
    while (i < N) {
        int j = i;
        while (j < N && sorted[j].first == sorted[i].first) {
            ++j;
        }
        // All indices from i to j-1 have the same canonical form.
        // The lowest possible original position for any of these is (i+1).
        // The highest possible original position for any of these is (j).
        for (int k = i; k < j; ++k) {
            int idx = sorted[k].second;
            lo[idx] = i + 1;
            hi[idx] = j;  // j is the count, which equals the last possible position
        }
        i = j;
    }

    for (int i = 0; i < N; ++i) {
        cout << lo[i] << " " << hi[i] << "\n";
    }

    return 0;
}
